code = """import json
import pandas as pd
from datetime import datetime
import re

# Load the query results
query_results = locals()['var_functions.query_db:5']
if isinstance(query_results, str) and query_results.endswith('.json'):
    # Load from file if it's a file path
    with open(query_results, 'r') as f:
        patents_data = json.load(f)
else:
    patents_data = query_results

print(f"Total patents retrieved: {len(patents_data)}")

# Show first few grant_date formats
print("Sample grant_date formats:")
for i, record in enumerate(patents_data[:10]):
    print(f"  {i+1}: '{record.get('grant_date', 'N/A')}'")

# Try to extract year from grant_date to see if we have 2019 data
print("\nExtracting years from grant_date:")
years = []
for record in patents_data:
    grant_date = record.get('grant_date', '')
    if grant_date:
        # Find 4-digit year pattern
        year_match = re.search(r'(\d{4})', grant_date)
        if year_match:
            years.append(year_match.group(1))

unique_years = sorted(list(set(years)))
print(f"Years found in data: {unique_years}")

# Count patents by year
from collections import Counter
year_counts = Counter(years)
print(f"\nPatent counts by year: {dict(year_counts)}")

# Check if we have 2019 data
if '2019' in year_counts:
    print(f"\nFound {year_counts['2019']} patents from 2019")
else:
    print("\nNo 2019 patents found in this dataset")"""

